class ProfilePlugin extends FeaturePlugin {
  @override
  Map<String, WidgetBuilder>? getRoutes() => {
    '/profile': (_) => BlocProvider(
      create: (_) => ProfileBloc(adapterRegistry.getRepository<AuthRepository>())..add(LoadProfileEvent()),
      child: ProfileScreen(),
    ),
  };
}

final productId = routeArgs is Map ? routeArgs['productId'] as String : routeArgs as String;
if (!_detailBlocs.containsKey(productId)) {
  _detailBlocs[productId] = ProductsBloc(...)..add(LoadProductDetailEvent(productId));
}
return BlocProvider.value(value: _detailBlocs[productId]!, child: ProductDetailScreen(pageConfig: pageConfig));
